@namespace Lumeo
@implements IAsyncDisposable
@inject IComponentInteropService Interop

<div id="@_id" class="@CssClass" role="radiogroup" @onkeydown="HandleKeyDown" @attributes="AdditionalAttributes">
    @if (Options is not null)
    {
        @* Data-driven mode: a flat List<SegmentedOption> handed in via the
           Options parameter. Original API; kept verbatim. *@
        @foreach (var option in Options)
        {
            var isActive = option.Value == _value;
            <button type="button"
                    id="@OptionId(option.Value)"
                    role="radio"
                    aria-checked="@isActive.ToString().ToLower()"
                    tabindex="@GetTabIndex(option.Value, option.Disabled)"
                    class="@GetItemClasses(isActive)"
                    disabled="@option.Disabled"
                    @onclick="() => SelectOption(option.Value)">
                @if (option.IconContent is not null)
                {
                    <span class="me-1.5">@option.IconContent</span>
                }
                @option.Label
            </button>
        }
    }
    else if (ChildContent is not null)
    {
        @* Compound mode: <SegmentedItem Value="..."> children register
           themselves via the cascading context. Matches the shadcn-style
           composition the rest of the library uses (TabsTrigger, SelectItem,
           …) and is what the docs reach for. *@
        <CascadingValue Value="@_context" IsFixed="false">
            @ChildContent
        </CascadingValue>
    }
</div>

@code {
    [Parameter] public string? Value { get; set; }
    [Parameter] public EventCallback<string> ValueChanged { get; set; }
    /// <summary>Data-driven options. When set, takes precedence over
    /// <see cref="ChildContent"/>. Leave null and pass <see cref="SegmentedItem"/>
    /// children for the compound-component flavour.</summary>
    [Parameter] public List<SegmentedOption>? Options { get; set; }
    /// <summary>Compound-mode content — one or more <see cref="SegmentedItem"/>.
    /// Ignored when <see cref="Options"/> is set.</summary>
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public bool Block { get; set; }
    /// <summary>Per-control density override. When null, inherits from any
    /// ancestor <see cref="DensityScope"/>; if neither is set, matches the
    /// historical <c>Comfortable</c> default. Only the track + item padding
    /// shift between values.</summary>
    [Parameter] public Density? Density { get; set; }
    [CascadingParameter] private Density? InheritedDensity { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private SegmentedContext _context = default!;
    private readonly string _id = LumeoIds.New("segmented");

    // Live selected value. Decoupled from the [Parameter] Value — mutated
    // OPTIMISTICALLY by SelectOption — so the framework's parameter-binding
    // never silently snaps it back, and OnParametersSet below decides exactly
    // when to (re)adopt it.
    private string? _value;
    // Last-seen bound parameter — lets the UNCONTROLLED branch distinguish "the
    // parent genuinely changed Value" from "a plain re-render re-supplied the
    // same literal" (which must not clobber the user's selection).
    private string? _lastValueParam;
    // CONTROLLED discriminator: the last value we pushed UP via ValueChanged
    // (also re-synced whenever we adopt an authoritative Value). A controlled
    // parent re-render that echoes back this exact value is safe to ignore (keep
    // in-flight state); any other value is an authoritative assertion
    // (normalization / veto / reset) and must win — that's what rolls a rejected
    // selection back to the bound value.
    private string? _lastPushed;

    // Ordered item registry — one entry per segment in DOM/declaration order.
    // In Options mode it is rebuilt from Options every parameter set; in compound
    // mode SegmentedItem children register/replace/unregister themselves keyed by
    // their STABLE ItemId (never by Value), exactly like Accordion's trigger
    // registry. Drives roving tabindex (only ONE item is in the tab sequence) and
    // arrow-key navigation between segments — both resolve "current position" by
    // index into this list, so the live DOM order is authoritative.
    //
    // Why an ordered list keyed by ItemId rather than a List<string> + two
    // Value-keyed dictionaries (the previous shape): SegmentedItem.Value is
    // [EditorRequired] but not enforced unique, and it can change at runtime.
    // Keying the registry by Value (a) collapsed duplicate-Value siblings into one
    // slot and (b) on a Value change forced an unregister+append that moved the
    // segment to the TAIL of the list, scrambling navigation order. Keying every
    // mutation by the stable ItemId — and rewriting the entry IN PLACE on a Value
    // change — preserves each segment's declared slot. (#63)
    private readonly List<SegmentedItemEntry> _items = new();

    // Stable per-option element id (Options mode). Indexed rather than slugged
    // from the value so it is always a valid HTML id regardless of value text.
    private string OptionId(string value)
    {
        var idx = _items.FindIndex(i => i.Value == value);
        return idx >= 0 ? _items[idx].ItemId : $"{_id}-opt{Options?.FindIndex(o => o.Value == value) ?? -1}";
    }

    private Lumeo.Density EffectiveDensity => Density ?? InheritedDensity ?? Lumeo.Density.Comfortable;

    // Track padding tracks density; Comfortable reproduces the historical p-1.
    private string TrackPadClass => EffectiveDensity switch
    {
        Lumeo.Density.Compact => "p-0.5",
        Lumeo.Density.Spacious => "p-1.5",
        _ => "p-1"
    };

    // Item padding tracks density; Comfortable reproduces the historical px-3 py-1.5.
    private string ItemPadClass => EffectiveDensity switch
    {
        Lumeo.Density.Compact => "px-2 py-1",
        Lumeo.Density.Spacious => "px-4 py-2",
        _ => "px-3 py-1.5"
    };

    protected override void OnParametersSet()
    {
        if (ValueChanged.HasDelegate)
        {
            // CONTROLLED: the parent owns Value.
            // Echo of our own push (Value == _lastPushed) → keep in-flight backing state.
            // Anything else (veto, normalization, reset) → adopt the parent's assertion.
            if (Value != _lastPushed)
            {
                _value = Value;
                _lastPushed = Value;
            }
        }
        else if (Value != _lastValueParam)
        {
            // UNCONTROLLED: component owns the live value.
            // Adopt the parameter only when the parent genuinely changes it; a stale
            // re-render that re-supplies the same literal must not clobber the user's selection.
            _value = Value;
            _lastPushed = Value;
        }
        // Keep the uncontrolled discriminator pointing at the last Value we observed.
        _lastValueParam = Value;

        if (Options is not null)
        {
            // Rebuild the ordered registry from the declarative Options each
            // parameter set so reordering / disabling stays in sync for arrow
            // navigation. Each option's element id is positional and stable.
            _items.Clear();
            var seen = new HashSet<string>();
            for (var i = 0; i < Options.Count; i++)
            {
                var opt = Options[i];
                if (!seen.Add(opt.Value))
                    throw new InvalidOperationException(
                        $"Duplicate SegmentedOption.Value '{opt.Value}' is not supported — each option needs a unique Value.");
                _items.Add(new SegmentedItemEntry(opt.Value, $"{_id}-opt{i}", opt.Disabled));
            }
        }

        _context = new SegmentedContext(
            _value,
            EventCallback.Factory.Create<string>(this, SelectOption),
            GetItemClasses,
            GetTabIndex,
            _items,
            RegisterItem,
            ReplaceItem,
            UnregisterItem,
            _id);
    }

    // --- Compound-mode registry mutations, all keyed by the STABLE ItemId ---
    // (mirrors Accordion.RegisterTrigger / ReplaceTrigger / UnregisterTrigger)

    // Add a segment to the ordered list (or refresh it in place if it is already
    // present under this ItemId). Append preserves declaration order because
    // SegmentedItem children register top-to-bottom on first render.
    private void RegisterItem(string value, string itemId, bool disabled)
    {
        var idx = _items.FindIndex(i => i.ItemId == itemId);
        if (idx >= 0) _items[idx] = new SegmentedItemEntry(value, itemId, disabled);
        else _items.Add(new SegmentedItemEntry(value, itemId, disabled));
    }

    // Re-key an existing segment IN PLACE when its Value changes at runtime. The
    // ItemId is stable across a Value change, so resolve the slot by ItemId and
    // only rewrite Value/Disabled — keeping the original slot preserves DOM order
    // (a naive unregister+append would scramble it) AND is safe when several
    // segments share the old/new Value. Exactly Accordion.ReplaceTrigger.
    private void ReplaceItem(string oldValue, string newValue, string itemId, bool disabled)
    {
        var idx = _items.FindIndex(i => i.ItemId == itemId);
        if (idx >= 0) _items[idx] = new SegmentedItemEntry(newValue, itemId, disabled);
        else RegisterItem(newValue, itemId, disabled);
    }

    // Remove a conditionally-removed segment by its stable ItemId so a
    // duplicate-Value sibling's slot is never collateral-deleted.
    private void UnregisterItem(string itemId)
    {
        var idx = _items.FindIndex(i => i.ItemId == itemId);
        if (idx >= 0) _items.RemoveAt(idx);
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (!firstRender) return;
        try
        {
            // Suppress page scroll for the keys the radiogroup consumes. A native
            // key-selective preventDefault is the only race-free way to cancel the
            // current event (Blazor's @onkeydown:preventDefault lags one keystroke).
            await Interop.RegisterPreventDefaultKeys(
                _id,
                new[] { "ArrowDown", "ArrowRight", "ArrowUp", "ArrowLeft", "Home", "End" }
                    .Select(k => new Lumeo.Services.PreventDefaultKeyRule(k)).ToArray());
            _pdRegistered = true;
        }
        catch (JSDisconnectedException) { }
        catch (ObjectDisposedException) { }
        catch (InvalidOperationException) { } // JS interop unavailable during prerender
    }

    private string CssClass => Cx.Merge(
        "inline-flex items-center rounded-lg bg-muted",
        TrackPadClass,
        Cx.When(Block, "w-full"),
        Class);

    private string GetItemClasses(bool isActive) => isActive
        ? Cx.Join(
            "inline-flex items-center justify-center rounded-md bg-background text-sm font-medium text-foreground shadow-sm transition-all focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-1",
            ItemPadClass,
            Cx.When(Block, "flex-1"))
        : Cx.Join(
            "inline-flex items-center justify-center rounded-md text-sm text-muted-foreground transition-all hover:text-foreground focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-1 disabled:pointer-events-none disabled:opacity-50",
            ItemPadClass,
            Cx.When(Block, "flex-1"));

    private async Task SelectOption(string value)
    {
        // Mutate the working backing field only — NEVER the [Parameter] Value.
        // Record _lastPushed BEFORE invoking ValueChanged: a controlled parent
        // re-renders synchronously inside InvokeAsync, so OnParametersSet must
        // already see this value as "the value we just pushed" to distinguish an
        // accepted echo (keep in-flight state) from a veto (parent kept its old
        // value → roll back).
        _value = value;
        _lastPushed = value;
        await ValueChanged.InvokeAsync(value);
    }

    // Roving tabindex: only the selected segment (or, when nothing is selected,
    // the first ENABLED segment) is in the tab sequence. Everything else is
    // tabindex=-1 and reachable only via arrow keys. The "first enabled" fallback
    // walks the ordered registry, so it tracks live DOM order.
    private string GetTabIndex(string value, bool disabled)
    {
        if (disabled) return "-1";
        // A selected Value that is missing or itself disabled can't hold the tab
        // stop — fall back to the first enabled segment so the radiogroup always
        // has exactly one entry point.
        var selectedIsEnabled = !string.IsNullOrEmpty(_value)
            && _items.Any(i => i.Value == _value) && !IsItemDisabledIn(_items, _value);
        if (selectedIsEnabled && _value == value) return "0";
        if (!selectedIsEnabled
            && FirstEnabledValue(_items) == value) return "0";
        return "-1";
    }

    // First enabled Value walking the supplied (registry- or DOM-ordered) list.
    private static string? FirstEnabledValue(IReadOnlyList<SegmentedItemEntry> items)
    {
        foreach (var item in items)
            if (!item.Disabled) return item.Value;
        return null;
    }

    // Resolve disabled state by walking the supplied list. When two segments share
    // a Value (legal in compound mode) the FIRST entry decides — which is the slot
    // that also holds the lone tab stop, so the two stay consistent.
    private static bool IsItemDisabledIn(IReadOnlyList<SegmentedItemEntry> items, string value)
    {
        foreach (var item in items)
            if (item.Value == value) return item.Disabled;
        return false;
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (_items.Count == 0) return;

        // Compute the navigation intent FIRST and bail before any JS interop when the
        // key isn't one we handle (mirrors RadioGroupItem: direction first, early-out,
        // THEN probe the DOM). `direction` encodes the arrows; Home/End below.
        var direction = e.Key switch
        {
            "ArrowDown" or "ArrowRight" => 1,
            "ArrowUp" or "ArrowLeft" => -1,
            _ => 0
        };
        var isHome = e.Key == "Home";
        var isEnd = e.Key == "End";
        if (direction == 0 && !isHome && !isEnd) return;

        // Resolve the nav order from the LIVE DOM (#63): a keyed reorder MOVES reused
        // SegmentedItem instances to new positions WITHOUT firing OnParametersSet, and
        // a middle-INSERT lands the new child at the registry TAIL (RegisterItem
        // appends) — both leave the C# declaration-order registry stale. The DOM-order
        // probe re-derives the true on-screen order. Falls back to the registry order
        // when the probe is unavailable (prerender / JS off / tests that don't drive a
        // reorder), so EVERY existing behaviour is unchanged.
        var items = await OrderedItems();

        // The "current" segment for navigation is the selected one, falling back
        // to the first enabled segment (which holds the lone tab stop). Resolve its
        // position by INDEX into the ordered list so navigation follows live DOM
        // order even after an in-place Value re-key or a keyed reorder.
        var currentIdx = !string.IsNullOrEmpty(_value) && items.Any(i => i.Value == _value) && !IsItemDisabledIn(items, _value)
            ? items.FindIndex(i => i.Value == _value)
            : items.FindIndex(i => !i.Disabled);
        if (currentIdx < 0) return;

        string? target =
            direction != 0 ? FindNextEnabled(items, currentIdx, direction)
            : isHome ? FirstEnabledValue(items)
            : LastEnabledValue(items);
        if (target is null) return;

        // Radiogroup model: arrows move selection AND focus together.
        await SelectOption(target);
        var targetIdx = items.FindIndex(i => i.Value == target);
        if (targetIdx >= 0)
        {
            try { await Interop.FocusElement(items[targetIdx].ItemId); }
            catch (JSDisconnectedException) { }
        }
    }

    // The registry (_items) reordered to match live DOM order. The DOM-order probe
    // returns the role=radio ids in document order; we reproject the registry entries
    // onto it (skipping ids the DOM didn't surface, then appending any registry
    // leftovers). An empty/NULL probe result → use the registry order verbatim.
    private async Task<List<SegmentedItemEntry>> OrderedItems()
    {
        var registry = _items;
        // NOTE: a Loose-mode JSInterop (the default test double) returns NULL for an
        // unconfigured string[] invocation — null-guard it, don't assume [].
        string[]? domOrder;
        try
        {
            domOrder = await Interop.GetOrderedDescendantIds(_id, "[role='radio']");
        }
        catch (JSDisconnectedException) { domOrder = null; }
        catch (ObjectDisposedException) { domOrder = null; }
        catch (InvalidOperationException) { domOrder = null; } // JS unavailable (prerender)

        if (domOrder is not { Length: > 0 }) return registry;

        var byId = registry.ToDictionary(i => i.ItemId);
        var ordered = new List<SegmentedItemEntry>(registry.Count);
        foreach (var id in domOrder)
            if (byId.Remove(id, out var item)) ordered.Add(item);
        ordered.AddRange(byId.Values);
        return ordered;
    }

    private static string? LastEnabledValue(IReadOnlyList<SegmentedItemEntry> items)
    {
        for (var i = items.Count - 1; i >= 0; i--)
            if (!items[i].Disabled) return items[i].Value;
        return null;
    }

    private static string? FindNextEnabled(IReadOnlyList<SegmentedItemEntry> items, int currentIdx, int direction)
    {
        if (items.Count == 0) return null;
        var idx = currentIdx;
        for (var i = 0; i < items.Count; i++)
        {
            idx += direction;
            if (idx < 0) idx = items.Count - 1;
            else if (idx >= items.Count) idx = 0;
            if (idx == currentIdx) return null;
            if (!items[idx].Disabled) return items[idx].Value;
        }
        return null;
    }

    private bool _pdRegistered;

    public async ValueTask DisposeAsync()
    {
        if (!_pdRegistered) return;
        try { await Interop.UnregisterPreventDefaultKeys(_id); }
        catch (JSDisconnectedException) { }
        catch (ObjectDisposedException) { }
        catch (InvalidOperationException) { }
    }

    public class SegmentedOption
    {
        public string Label { get; set; } = "";
        public string Value { get; set; } = "";

        /// <summary>Icon slot. Named <c>IconContent</c> to avoid shadowing the <c>&lt;Icon&gt;</c> component.</summary>
        public RenderFragment? IconContent { get; set; }

        public bool Disabled { get; set; }
    }

    /// <summary>One entry in the ordered segment registry: the segment's current
    /// <paramref name="Value"/>, its STABLE <paramref name="ItemId"/> (the key for
    /// every registry mutation — survives a Value change) and its current
    /// <paramref name="Disabled"/> state.</summary>
    public readonly record struct SegmentedItemEntry(string Value, string ItemId, bool Disabled);

    /// <summary>Cascading context for compound-mode <see cref="SegmentedItem"/>
    /// children — they read the active value + the parent's item-class function
    /// (so style stays consistent with Options-mode), register / re-key / unregister
    /// themselves in the shared ordered registry (for roving tabindex + arrow
    /// navigation) keyed by their stable ItemId, and invoke <see cref="Select"/> on
    /// click.</summary>
    public sealed record SegmentedContext(
        string? Value,
        EventCallback<string> Select,
        Func<bool, string> GetItemClasses,
        Func<string, bool, string> GetTabIndex,
        IReadOnlyList<SegmentedItemEntry> Items,
        Action<string, string, bool> RegisterItem,
        Action<string, string, string, bool> ReplaceItem,
        Action<string> UnregisterItem,
        // The role=radiogroup element id — the anchor for the DOM-order roving-nav
        // probe (Interop.GetOrderedDescendantIds) so arrow-key order tracks the live
        // DOM after a keyed reorder / middle-insert of SegmentedItem children.
        string ContainerId);
}

@namespace Lumeo
@implements IDisposable

@if (Context is not null)
{
    var isActive = Value == Context.Value;
    <button type="button"
            id="@_itemId"
            role="radio"
            aria-checked="@isActive.ToString().ToLower()"
            tabindex="@Context.GetTabIndex(Value, Disabled)"
            class="@Context.GetItemClasses(isActive)"
            disabled="@Disabled"
            @onclick="HandleClick"
            @attributes="AdditionalAttributes">
        @if (IconContent is not null)
        {
            <span class="me-1.5">@IconContent</span>
        }
        @ChildContent
    </button>
}

@code {
    [CascadingParameter] public Segmented.SegmentedContext? Context { get; set; }

    /// <summary>The value selected when this item is clicked. Must match one of
    /// the parent <see cref="Segmented"/>'s expected values.</summary>
    [Parameter, EditorRequired] public string Value { get; set; } = "";

    [Parameter] public RenderFragment? ChildContent { get; set; }

    /// <summary>Optional leading icon slot.</summary>
    [Parameter] public RenderFragment? IconContent { get; set; }

    [Parameter] public bool Disabled { get; set; }

    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private readonly string _itemId = LumeoIds.New("segmented-item");
    private string? _registeredValue;

    protected override void OnParametersSet()
    {
        if (Context is null) return;

        // #63 (pure @key physical-reorder-with-reuse leg) + the middle-INSERT leg:
        // when two segments swap DOM position via @key, Blazor REUSES each component
        // instance with IDENTICAL parameters — Value/Disabled are unchanged, so
        // OnParametersSet here sees no diff and never re-keys the registry; and a
        // brand-new child inserted in the MIDDLE registers at the registry TAIL
        // (RegisterItem appends), not its DOM slot. Either way the declaration-order
        // registry no longer matches the visual order. Those legs are NOW resolved at
        // NAVIGATION time by the parent (Segmented.HandleKeyDown) consulting the
        // shared DOM-order probe (Interop.GetOrderedDescendantIds) to re-derive the
        // true on-screen order before computing the arrow-key neighbour, so this
        // registration logic only needs to keep the entry present + current. The
        // three OnParametersSet-observable legs — own-Value change, middle-insert and
        // middle-remove — keep the entry correct below.

        // Register / re-key into the parent's shared ordered registry keyed by our
        // STABLE _itemId (never by Value), so roving tabindex + arrow navigation see
        // this segment in its declared DOM slot with its current Disabled state.
        if (_registeredValue is null)
        {
            // First parameter set: take a slot at the tail (children register
            // top-to-bottom, so append preserves declaration order).
            Context.RegisterItem(Value, _itemId, Disabled);
        }
        else if (_registeredValue != Value)
        {
            // Our OWN Value changed at runtime: rewrite the existing slot IN PLACE
            // (resolved by _itemId) instead of remove-then-append, so the segment
            // keeps its position — exactly Accordion.ReplaceTrigger. A duplicate-
            // Value sibling's slot is untouched because we key by _itemId.
            Context.ReplaceItem(_registeredValue, Value, _itemId, Disabled);
        }
        else
        {
            // Same Value, possibly new Disabled state: refresh in place.
            Context.RegisterItem(Value, _itemId, Disabled);
        }
        _registeredValue = Value;
    }

    private async Task HandleClick()
    {
        if (Context is null || Disabled) return;
        await Context.Select.InvokeAsync(Value);
    }

    public void Dispose()
    {
        // Conditionally-removed segments must leave the registry. Unregister by our
        // stable _itemId so a duplicate-Value sibling's slot is never deleted.
        Context?.UnregisterItem(_itemId);
    }
}
